    {
      "id": "auth-endpoints",
      "prompt": "Genera endpoints de autenticacion con JWT",
      "expected_behavior": "Genera login y register con middleware de auth",
      "assertions": [
        {"type": "content_contains", "file": "routes/auth.ts", "text": "jwt"}
      ]
